function solve(n: number, edges: number[][], k: number): number {
    edges.sort((a, b) => a[2] - b[2]);
    const weights = edges.map(e => e[2]);
    let low = 0;
    let high = weights[weights.length - 1];
    let answer = high;

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        let left = 0, right = edges.length - 1;
        let idx = edges.length;

        while (left <= right) {
            const mid2 = Math.floor((left + right) / 2);
            if (edges[mid2][2] <= mid) {
                left = mid2 + 1;
            } else {
                right = mid2 - 1;
            }
        }
        idx = right + 1;

        const parent = Array(n).fill(0).map((_, i) => i);
        const rank = Array(n).fill(0);

        function find(u: number): number {
            if (parent[u] !== u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        }

        function union(u: number, v: number): boolean {
            const rootU = find(u);
            const rootV = find(v);
            if (rootU === rootV) return false;
            if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                if (rank[rootU] === rank[rootV]) {
                    rank[rootU]++;
                }
            }
            return true;
        }

        for (let i = 0; i < idx; i++) {
            const [u, v, w] = edges[i];
            union(u, v);
        }

        const roots = new Set<number>();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        const numComponents = roots.size;

        if (numComponents <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
