            if (parent[u] !== u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        };

        const union = (u: number, v: number): void => {
            const rootU = find(u);
            const rootV = find(v);
            if (rootU !== rootV) {
                parent[rootV] = rootU;
            }
        };

        for (let i = 0; i < index; i++) {
            const [u, v, w] = edges[i];
            union(u, v);
        }

        const roots = new Set<number>();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        const numComponents = roots.size;

        if (numComponents <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
